CustomField.formula:
IF(
    OR(
        ISPICKVAL(Status, "Completed"),
        ISPICKVAL(Status, "Rejected"),
        ISPICKVAL(Status, "Failed")
    ),
    /* If Status is Completed/Rejected/Failed */
    IF(
        OR(
            ISBLANK(Last_Completed_Date__c),
            ISBLANK(Gallons_Per_Month__c),
            ISBLANK(Optimo_Date__c)
        ),
        0,
        MAX(0, (Gallons_Per_Month__c / 30) * (Optimo_Date__c - Last_Completed_Date__c))
    ),
    /* If Status is anything else (Draft, In Progress, etc.) */
    IF(
        OR(
            ISBLANK(Last_Completed_Date__c),
            ISBLANK(Gallons_Per_Month__c)
        ),
        0,
        MAX(0, (Gallons_Per_Month__c / 30) * (TODAY() - Last_Completed_Date__c))
    )
)
